-- Generated migration: 30 grammar rules (SLIM shape)
-- Use this ONLY if you skipped section 3b in 01_schema.sql.
-- NOTE: this drops category, colour, icon, uses, signals and mistakes
-- data from the original GRAM array -- there is no column for them
-- in the slim schema. Prefer seed_grammar.sql + schema section 3b.

insert into public.grammar (id, title, subtitle, formula, tip, examples, quiz)
values
('g1', 'Simple Present', 'Habits, facts & routines', 'Subject + V(s/es)', '💡 Add -s/-es for He/She/It: go→goes, watch→watches, study→studies', '[{"en":"She works at a hospital.","pt":"Ela trabalha num hospital."},{"en":"Do you speak English?","pt":"Falas inglês?"},{"en":"The Earth revolves around the Sun.","pt":"A Terra gira em torno do Sol."}]'::jsonb, '[{"q":"Which is correct?","opts":["She go.","She goes.","She is go.","She going."],"ans":1},{"q":"\"He ___ like coffee.\"","opts":["don''t","doesn''t","not","isn''t"],"ans":1}]'::jsonb),
('g2', 'Present Continuous', 'Ongoing actions right now', 'Subject + am/is/are + V-ing', '💡 Stative verbs can''t use -ing: know, love, want, need, like, believe', '[{"en":"I am studying English right now.","pt":"Estou a estudar inglês agora."},{"en":"Are you listening to me?","pt":"Estás a ouvir-me?"},{"en":"They are building a new school.","pt":"Eles estão a construir uma escola."}]'::jsonb, '[{"q":"\"Look! It ___ (rain)\"","opts":["rains","rained","is raining","has rained"],"ans":2},{"q":"Which is WRONG?","opts":["I am eating.","She is running.","They are knowing.","We are waiting."],"ans":2}]'::jsonb),
('g3', 'Present Perfect', 'Past actions with present impact', 'Subject + have/has + Past Participle', '💡 Simple Past with specific time: "I went yesterday." Present Perfect with no time or since/for.', '[{"en":"I have never eaten sushi.","pt":"Nunca comi sushi."},{"en":"She has already left.","pt":"Ela já foi embora."},{"en":"Have you finished your homework?","pt":"Já terminaste a tua tarefa?"}]'::jsonb, '[{"q":"\"Have you ___ seen a lion?\"","opts":["ever","just","since","yet"],"ans":0},{"q":"\"She ___ just finished.\"","opts":["have","has","had","did"],"ans":1}]'::jsonb),
('g4', 'Simple Past', 'Completed past actions', 'Subject + V-ed / V2 (irregular)', '💡 Irregular verbs: go→went, buy→bought, eat→ate, see→saw, come→came', '[{"en":"She walked to school yesterday.","pt":"Ela foi à escola a pé ontem."},{"en":"Did you see the match last night?","pt":"Viste o jogo ontem à noite?"},{"en":"We bought a new car last year.","pt":"Comprámos um carro novo no ano passado."}]'::jsonb, '[{"q":"\"She ___ a letter.\" (write, past)","opts":["writed","wrote","has written","writing"],"ans":1},{"q":"\"___ you see the game?\"","opts":["Did","Do","Have","Were"],"ans":0}]'::jsonb),
('g5', 'Modal Verbs', 'can, should, must, might...', 'Subject + modal + base verb', '💡 Modals NEVER take -s for He/She/It: "She can swim" ✓ NOT "She cans swim" ✗', '[{"en":"You should study more.","pt":"Deves estudar mais."},{"en":"She can speak three languages.","pt":"Ela consegue falar três línguas."},{"en":"It might snow tonight.","pt":"Pode nevar esta noite."}]'::jsonb, '[{"q":"\"You ___ see a doctor. You look terrible.\"","opts":["must to","should","can","might to"],"ans":1},{"q":"\"She ___ swim when she was 5.\"","opts":["can","could","should","must"],"ans":1}]'::jsonb),
('g6', 'Conditionals', 'If this, then that', 'If + condition, result', '💡 In 2nd Conditional, use "were" for all subjects: "If I WERE you..." (not "was").', '[{"en":"If you heat ice, it melts.","pt":"Se aqueceres gelo, ele derrete."},{"en":"If I have time, I will call you.","pt":"Se tiver tempo, ligo-te."},{"en":"If I were rich, I would travel.","pt":"Se fosse rico, viajaria."}]'::jsonb, '[{"q":"\"If it rains, she ___ stay home.\"","opts":["would","will","stay","stayed"],"ans":1},{"q":"\"If I were rich, I ___ travel.\"","opts":["will","would","am","should"],"ans":1}]'::jsonb),
('g7', 'Articles: A / An / The', 'The most confusing 3 words in English', 'A + consonant sound | An + vowel sound | The = specific', '💡 AN before vowel SOUNDS: "an hour" (h is silent!) / "a university" (sounds like "you"!)', '[{"en":"She is a doctor.","pt":"Ela é médica."},{"en":"The doctor I like is Dr. Silva.","pt":"O médico de quem gosto é o Dr. Silva."},{"en":"He plays the piano.","pt":"Ele toca piano."}]'::jsonb, '[{"q":"Choose: \"She is ___ engineer.\"","opts":["a","an","the","—"],"ans":1},{"q":"Choose: \"___ Amazon is the largest river.\"","opts":["A","An","The","—"],"ans":2}]'::jsonb),
('g8', 'Passive Voice', 'The action matters, not the doer', 'Subject + be + Past Participle (+ by...)', '💡 "By" introduces the agent (doer). Without "by" = unknown doer.', '[{"en":"The book was written by Couto.","pt":"O livro foi escrito pelo Couto."},{"en":"English is spoken worldwide.","pt":"O inglês é falado em todo o mundo."},{"en":"My phone was stolen!","pt":"O meu telefone foi roubado!"}]'::jsonb, '[{"q":"\"The letter ___ yesterday.\" (write, passive)","opts":["wrote","was wrote","was written","is writing"],"ans":2},{"q":"Which is PASSIVE?","opts":["She cleaned the room.","The room was cleaned.","Cleaning the room.","She has cleaned it."],"ans":1}]'::jsonb),
('g9', 'Past Perfect', 'The past of the past — an action completed before another past action', 'Subject + had + Past Participle', '💡 Past Perfect is used to show which action happened first when two past actions are compared.', '[{"en":"She had already finished her homework when I called.","pt":"Ela já tinha terminado a lição de casa quando liguei."},{"en":"I had never seen such a beautiful place before I went to Italy.","pt":"Nunca tinha visto um lugar tão bonito antes de ir à Itália."},{"en":"By the time we arrived, the movie had already started.","pt":"Quando chegámos, o filme já tinha começado."},{"en":"He was tired because he had been working all day.","pt":"Ele estava cansado porque tinha estado a trabalhar o dia todo."}]'::jsonb, '[{"q":"\"She ___ already eaten when I arrived.\"","opts":["has","had","have","was"],"ans":1},{"q":"\"I ___ never ___ to Europe before.\"","opts":["have, be","had, been","has, been","had, be"],"ans":1},{"q":"\"By the time we got there, the party ___ started.\"","opts":["has","had","have","was"],"ans":1},{"q":"\"He was tired because he ___ all night.\"","opts":["worked","had worked","was working","has worked"],"ans":1}]'::jsonb),
('g10', 'Future Perfect', 'An action that will be completed before a specific future time', 'Subject + will have + Past Participle', '💡 Future Perfect focuses on completion before a specific future moment. Use "by" + a future time.', '[{"en":"By next year, I will have finished my degree.","pt":"Para o ano que vem, já terei terminado a minha licenciatura."},{"en":"She will have arrived by 5pm.","pt":"Ela já terá chegado até às 17h."},{"en":"They will have been married for 20 years in 2030.","pt":"Eles estarão casados há 20 anos em 2030."}]'::jsonb, '[{"q":"\"By 2030, I ___ for 10 years.\"","opts":["will work","will have worked","have worked","will be working"],"ans":1},{"q":"\"By the time you arrive, we ___ dinner.\"","opts":["will have","will have had","have","had"],"ans":1},{"q":"\"She ___ her homework by 8pm.\"","opts":["will finish","will have finished","finishes","finished"],"ans":1},{"q":"\"They ___ already ___ the report by Friday.\"","opts":["will, finish","will have, finished","have, finished","will be, finishing"],"ans":1}]'::jsonb),
('g11', 'Future Continuous', 'An action that will be in progress at a specific future time', 'Subject + will be + verb-ing', '💡 Future Continuous describes actions in progress at a specific future moment, not actions that are completed.', '[{"en":"This time next week, I will be lying on the beach.","pt":"Para a semana a esta hora, estarei deitado na praia."},{"en":"She will be working when you call her.","pt":"Ela estará a trabalhar quando ligares para ela."},{"en":"Will you be attending the meeting tomorrow?","pt":"Estarás a assistir à reunião amanhã?"}]'::jsonb, '[{"q":"\"This time tomorrow, I ___ on the beach.\"","opts":["will lie","will be lying","am lying","will have lain"],"ans":1},{"q":"\"At 10am, we ___ a meeting.\"","opts":["will have","will be having","are having","had"],"ans":1},{"q":"\"Will you ___ at the party tonight?\"","opts":["dance","be dancing","danced","have danced"],"ans":1},{"q":"\"I ___ for you when you arrive.\"","opts":["wait","will wait","will be waiting","will have waited"],"ans":2}]'::jsonb),
('g12', 'Mixed Conditionals', 'Combining past conditions with present results (and vice versa)', 'Type 1: If + Past Perfect, Would + infinitive (past condition → present result)
Type 2: If + Past Simple, Would have + PP (present condition → past result)', '💡 Mixed conditionals show the relationship between a past unreal condition and a present unreal result, or a present unreal condition and a past unreal result.', '[{"en":"If I had studied harder, I would be at university now.","pt":"Se tivesse estudado mais, estaria na universidade agora."},{"en":"If she were fluent in English, she would have gotten the job.","pt":"Se ela fosse fluente em inglês, teria conseguido o emprego."},{"en":"If I hadn''t met you, I would be lost.","pt":"Se não te tivesse conhecido, estaria perdido."}]'::jsonb, '[{"q":"\"If I had studied, I ___ a doctor now.\"","opts":["would be","would have been","am","was"],"ans":0},{"q":"\"If I were rich, I ___ that house.\"","opts":["would buy","would have bought","bought","had bought"],"ans":1},{"q":"\"If I hadn''t learned English, I ___ this job.\"","opts":["wouldn''t have","wouldn''t have had","wouldn''t have get","won''t have"],"ans":0},{"q":"\"If she ___ the meeting, she wouldn''t be so confused now.\"","opts":["attended","had attended","would attend","has attended"],"ans":1}]'::jsonb),
('g13', 'Reported Speech (Indirect Speech)', 'Reporting what someone said without quoting them directly', 'Reporting verb + (that) + subject + verb (with backshift)', '💡 When reporting speech, tenses often "backshift" (present becomes past, past becomes past perfect, etc.) and pronouns and time expressions may change.', '[{"en":"Direct: \"I am happy.\" → Reported: She said she was happy.","pt":"Directo: \"Estou feliz.\" → Indirecto: Ela disse que estava feliz."},{"en":"Direct: \"Where do you live?\" → Reported: He asked where I lived.","pt":"Directo: \"Onde vives?\" → Indirecto: Ele perguntou onde eu vivia."},{"en":"Direct: \"Don''t be late.\" → Reported: She warned me not to be late.","pt":"Directo: \"Não te atrases.\" → Indirecto: Ela avisou-me para não me atrasar."}]'::jsonb, '[{"q":"\"I am tired.\" → She said she ___ tired.","opts":["is","was","has been","had been"],"ans":1},{"q":"\"Where is the station?\" → He asked where the station ___.","opts":["is","was","has been","had been"],"ans":1},{"q":"\"Don''t touch that!\" → She warned me ___ that.","opts":["to touch","not to touch","don''t touch","that I don''t touch"],"ans":1},{"q":"\"I''ll help you.\" → He promised ___ me.","opts":["he helps","to help","he helped","that he help"],"ans":1}]'::jsonb),
('g14', 'Gerunds & Infinitives', 'Verb + -ing OR verb + to — which one?', 'Gerund: V-ing (as noun) | Infinitive: to + base verb', '💡 STOP + gerund = stop an activity. STOP + infinitive = stop in order to do something. "I stopped smoking" (quit) vs "I stopped to smoke" (paused in order to smoke).', '[{"en":"I enjoy swimming in the sea.","pt":"Gosto de nadar no mar."},{"en":"She decided to study abroad.","pt":"Ela decidiu estudar no estrangeiro."},{"en":"They finished writing the report.","pt":"Eles acabaram de escrever o relatório."}]'::jsonb, '[{"q":"\"I enjoy ___ movies.\" (watch)","opts":["to watch","watching","watch","watched"],"ans":1},{"q":"\"She decided ___ early.\" (leave)","opts":["leaving","leave","to leave","left"],"ans":2},{"q":"\"They finished ___ the project.\" (complete)","opts":["to complete","completing","complete","completed"],"ans":1},{"q":"\"He wants ___ a doctor.\" (be)","opts":["being","be","to be","been"],"ans":2}]'::jsonb),
('g15', 'Prepositions of Time & Place', 'at, in, on — never get confused again!', 'AT (point) | IN (enclosed space/period) | ON (surface/day)', '💡 "At night" but "in the morning/afternoon/evening". And: "at the end" (specific point) vs "in the end" (finally/ultimately).', '[{"en":"I wake up at 6am.","pt":"Acordo às 6h."},{"en":"She was born in 1998.","pt":"Ela nasceu em 1998."},{"en":"We meet on Fridays.","pt":"Encontramo-nos às sextas-feiras."}]'::jsonb, '[{"q":"\"I have a meeting ___ Monday ___ 9am.\"","opts":["on / at","in / on","at / in","on / in"],"ans":0},{"q":"\"She has lived here ___ 2019.\"","opts":["for","since","at","in"],"ans":1},{"q":"\"The keys are ___ the table.\"","opts":["in","at","on","for"],"ans":2},{"q":"\"I will finish ___ an hour.\"","opts":["since","at","in","on"],"ans":2}]'::jsonb),
('g16', 'Question Formation', 'Word order, auxiliary verbs & question words', 'Wh-word + Aux + Subject + Main verb? | Subject questions: no inversion', '💡 Subject questions: When WHO or WHAT is the SUBJECT, NO auxiliary needed and NO inversion: "Who called?" ✓ NOT "Who did call?" ✗. "What happened?" ✓ NOT "What did happen?" ✗', '[{"en":"Where do you work?","pt":"Onde trabalhas?"},{"en":"Who wrote this book?","pt":"Quem escreveu este livro?"},{"en":"You''re from Maputo, aren''t you?","pt":"És de Maputo, não és?"}]'::jsonb, '[{"q":"\"___ does she work?\" (place)","opts":["What","Who","Where","When"],"ans":2},{"q":"Choose the correct question:","opts":["Where you are going?","Where are you going?","Where do you going?","Where going you?"],"ans":1},{"q":"\"Who ___ the window?\" (break — subject question)","opts":["did break","broke","has broke","breaking"],"ans":1},{"q":"\"You like pizza, ___ you?\"","opts":["don''t","aren''t","isn''t","do"],"ans":0}]'::jsonb),
('g17', 'Essential Phrasal Verbs', 'The secret to sounding natural in English', 'Verb + Particle | Separable: "turn it off" | Inseparable: "look after him"', '💡 With separable phrasal verbs, PRONOUNS must go in the middle: "Turn it off" ✓ NOT "Turn off it" ✗. But nouns can go either place: "Turn off the TV" = "Turn the TV off".', '[{"en":"I gave up smoking last year.","pt":"Deixei de fumar no ano passado."},{"en":"Can you look after my dog?","pt":"Podes tomar conta do meu cão?"},{"en":"She came up with a great idea.","pt":"Ela teve uma grande ideia."}]'::jsonb, '[{"q":"\"She ___ a brilliant plan.\" (invented)","opts":["came up with","came with up","came up to","up came with"],"ans":0},{"q":"\"Don''t ___ the meeting.\" (postpone)","opts":["put off","put away","put down","put up"],"ans":0},{"q":"\"We ___ milk.\" (have no more)","opts":["ran out of","ran away from","ran out with","ran into"],"ans":0},{"q":"\"I can''t ___ the noise.\" (tolerate)","opts":["put up","put up with","put with up","put on with"],"ans":1}]'::jsonb),
('g18', 'Future Forms', 'will, going to, present continuous — all for the future!', 'WILL: spontaneous/predictions | GOING TO: planned | Pres.Cont.: arranged', '💡 "It''s going to rain" (you CAN SEE clouds — evidence now) vs "I think it will rain" (just a prediction with no current evidence). The clouds make all the difference!', '[{"en":"I''ll have the chicken, please.","pt":"Vou querer o frango, por favor."},{"en":"She''s going to start a new job.","pt":"Ela vai começar um novo emprego."},{"en":"We''re flying to Lisbon next week.","pt":"Voamos para Lisboa na semana que vem."}]'::jsonb, '[{"q":"The phone rings. You pick it up and say...","opts":["I''m going to answer it.","I answer it.","I''ll get it!","I''m getting it."],"ans":2},{"q":"\"Look at the sky — it ___ rain!\" (evidence)","opts":["will","is going to","is","rains"],"ans":1},{"q":"\"I ___ a concert next Saturday.\" (tickets bought)","opts":["will attend","attend","am attending","am going to attend"],"ans":2},{"q":"\"I ___ learn to drive one day.\" (vague intention)","opts":["''m going to","''ll","''m","am"],"ans":1}]'::jsonb),
('g19', 'Relative Clauses', 'Who, which, that, where, whose — linking ideas smoothly', 'Defining: [no commas, use that] | Non-defining: [with commas, no that]', '💡 In DEFINING clauses, THAT can replace who/which. In NON-DEFINING clauses (with commas), THAT is NOT possible. Never use that with commas!', '[{"en":"The woman who lives next door is a doctor.","pt":"A mulher que mora ao lado é médica."},{"en":"London, which is the capital of England, is very expensive.","pt":"Londres, que é a capital de Inglaterra, é muito cara."},{"en":"That''s the house where I was born.","pt":"É aquela a casa onde nasci."}]'::jsonb, '[{"q":"\"The student ___ got top marks is from Beira.\"","opts":["which","whose","who","where"],"ans":2},{"q":"\"This is the village ___ I was born.\"","opts":["which","who","whose","where"],"ans":3},{"q":"\"My car, ___ I bought last year, broke down.\"","opts":["that","which","who","whose"],"ans":1},{"q":"\"The man ___ car was stolen called the police.\"","opts":["who","which","whose","where"],"ans":2}]'::jsonb),
('g20', 'Countable & Uncountable Nouns', 'How many / How much — get it right every time', 'Countable: a/an, plural, many, few | Uncountable: no article/plural, much, little', '💡 Some nouns can be BOTH — with different meanings: "I''d like a coffee" (a cup of coffee) vs "I don''t like coffee" (the substance). Same with "a hair" (one strand) vs "hair" (in general).', '[{"en":"I have a little money but few friends.","pt":"Tenho pouco dinheiro mas poucos amigos."},{"en":"Could I have some water, please?","pt":"Podia me dar água, por favor?"},{"en":"How many chairs do you need?","pt":"De quantas cadeiras precisas?"}]'::jsonb, '[{"q":"Choose the correct sentence:","opts":["I need some informations.","I need an information.","I need some information.","I need informations."],"ans":2},{"q":"\"There isn''t ___ time.\"","opts":["many","few","much","a little much"],"ans":2},{"q":"\"She has very ___ friends.\"","opts":["much","little","few","less"],"ans":2},{"q":"\"Can I have ___ bread?\"","opts":["a","many","few","some"],"ans":3}]'::jsonb),
('g21', 'Adjective Order', 'Big red Italian car — why THIS specific order?', 'Opinion → Size → Age → Shape → Colour → Origin → Material → Purpose + Noun', '💡 Native speakers follow this order automatically and will feel something is "wrong" if you reverse it — even if they can''t explain why. Learn it as a rule and trust it!', '[{"en":"She drives a lovely little old red Italian sports car.","pt":"Ela conduz um lindo carrinho italiano vermelho antigo desportivo."},{"en":"He wore a beautiful long black silk scarf.","pt":"Ele usava um lindo cachecol longo de seda preta."},{"en":"They live in a small modern Japanese-style house.","pt":"Eles vivem numa casinha moderna de estilo japonês."}]'::jsonb, '[{"q":"Choose the correct order:","opts":["a red big old car","a big old red car","a old big red car","a red old big car"],"ans":1},{"q":"\"She wore a ___ silk scarf.\"","opts":["long beautiful black","beautiful black long","beautiful long black","black long beautiful"],"ans":2},{"q":"Which adjective type comes FIRST?","opts":["Colour","Origin","Opinion","Size"],"ans":2},{"q":"\"They have a ___ house.\"","opts":["brick small lovely old","lovely small old brick","old small lovely brick","small old lovely brick"],"ans":1}]'::jsonb),
('g22', 'Connectors & Linking Words', 'Because, although, however — making your English flow', 'Contrast | Cause | Result | Addition | Condition', '💡 "Despite" and "in spite of" MUST be followed by a NOUN or gerund — NOT a full clause. "Despite it was raining" ✗ → "Despite the rain" ✓ or "Despite it being rainy" ✓', '[{"en":"Although it was raining, we went for a walk.","pt":"Embora estivesse a chover, fomos dar uma volta."},{"en":"She studied hard; therefore, she passed the exam.","pt":"Ela estudou muito; por isso, passou no exame."},{"en":"Despite the heat, he wore a jacket.","pt":"Apesar do calor, ele usou um casaco."}]'::jsonb, '[{"q":"\"___ the cold weather, she wore a T-shirt.\"","opts":["Although","Despite","Because","However"],"ans":1},{"q":"\"He failed the test; ___, he tried again.\"","opts":["despite","although","however","because"],"ans":2},{"q":"\"___ it was late, she kept studying.\"","opts":["Despite","However","Although","Therefore"],"ans":2},{"q":"\"She studied hard. ___, she passed.\"","opts":["Although","Despite","Because","As a result"],"ans":3}]'::jsonb),
('g23', 'Quantifiers & Determiners', 'all, every, each, both, either, neither — mastered!', 'ALL (whole group) | EVERY (each, singular) | EACH (individual) | BOTH/EITHER/NEITHER (for two)', '💡 "Neither of them ARE/IS correct" — both forms are used, but IS is grammatically correct (formal). In casual speech, ARE is very common with NEITHER/EITHER of them.', '[{"en":"Every student needs a pen.","pt":"Cada aluno precisa de uma caneta."},{"en":"Both sisters are doctors.","pt":"As duas irmãs são médicas."},{"en":"Neither of the options is ideal.","pt":"Nenhuma das opções é ideal."}]'::jsonb, '[{"q":"\"___ student in the class passed.\"","opts":["All","Every","Both","Neither"],"ans":1},{"q":"\"___ the brothers work as teachers.\"","opts":["Each","Every","Both","Either"],"ans":2},{"q":"\"___ of the plans will work.\" (none)","opts":["Both","Either","Neither","Each"],"ans":2},{"q":"\"She visits ___ day.\" (daily)","opts":["all","every","each","both"],"ans":1}]'::jsonb),
('g24', 'Wish, If Only & I Wish', 'Expressing wishes about now and regrets about the past', 'WISH + Past Simple (present wish) | WISH + Past Perfect (past regret) | WISH + WOULD (annoying habit)', '💡 You CANNOT use "wish + would" about yourself: "I wish I would stop eating" ✗ → "I wish I could stop eating" ✓. Wish + would is only for someone ELSE''s behaviour.', '[{"en":"I wish I could speak Spanish.","pt":"Quem dera eu falar espanhol."},{"en":"She wishes she hadn''t said that.","pt":"Ela queria não ter dito isso."},{"en":"If only I had more time!","pt":"Oxalá eu tivesse mais tempo!"}]'::jsonb, '[{"q":"\"I wish I ___ taller.\" (present wish)","opts":["am","was/were","had been","will be"],"ans":1},{"q":"\"She wishes she ___ harder at school.\" (past regret)","opts":["studied","studies","had studied","would study"],"ans":2},{"q":"\"If only I ___ you the truth!\" (past regret)","opts":["told","tell","had told","would tell"],"ans":2},{"q":"\"I wish you ___ make so much noise!\" (annoying habit)","opts":["don''t","wouldn''t","didn''t","won''t"],"ans":1}]'::jsonb),
('g25', 'Advanced Passive Constructions', 'Modal passive, perfect passive & reporting structures', 'Modal passive: modal + be + PP | Perfect passive: have been + PP', '💡 Causative "have/get + object + PP" means you arranged for someone else to do it: "I cut my hair" (I did it myself) vs "I had my hair cut" (at the barber). Very common and useful!', '[{"en":"The project has been completed.","pt":"O projecto foi concluído."},{"en":"The rules must be followed.","pt":"As regras devem ser seguidas."},{"en":"It is reported that prices will rise.","pt":"É noticiado que os preços vão subir."}]'::jsonb, '[{"q":"\"The homework ___ before Friday.\" (must)","opts":["must finish","must be finish","must be finished","must finished"],"ans":2},{"q":"\"The bridge ___ in 1905.\" (build, past passive)","opts":["built","was built","has built","is built"],"ans":1},{"q":"\"The results ___ yet.\" (not announce, present perfect passive)","opts":["haven''t announced","haven''t been announced","aren''t announced","weren''t announced"],"ans":1},{"q":"\"___ that the economy will recover.\"","opts":["People believe","It is believed","Believed it is","It believes"],"ans":1}]'::jsonb),
('g26', 'Emphasis & Cleft Sentences', 'It was HER who called — making specific ideas stand out', 'IT + be + focus + THAT/WHO | WHAT + clause + be + focus', '💡 Inversion after negative adverbials (Never, Rarely, Seldom, Not only, Little did...) is very FORMAL — perfect for essays, academic writing and impressive speeches!', '[{"en":"It is hard work that leads to success.","pt":"É o trabalho árduo que leva ao sucesso."},{"en":"What I really want is a holiday.","pt":"O que eu realmente quero é umas férias."},{"en":"Never have I been so embarrassed!","pt":"Nunca me senti tão envergonhado!"}]'::jsonb, '[{"q":"\"___ was her smile that won everyone over.\"","opts":["That","What","It","Which"],"ans":2},{"q":"\"___ I really hate is traffic jams.\"","opts":["It","That","What","Which"],"ans":2},{"q":"\"I ___ like your new haircut!\" (emphasis)","opts":["really do","do really","really","just do"],"ans":0},{"q":"\"Never ___ I eaten something so delicious!\"","opts":["I have","have","did","I did"],"ans":1}]'::jsonb),
('g27', 'Comparatives & Superlatives', 'Bigger, the biggest — and all the tricky exceptions', 'Short adj: -er / the -est | Long adj: more/most | Irregular: good→better→best', '💡 Never double-compare: "more better" ✗ / "more faster" ✗ / "the most tallest" ✗. The -er ending already MEANS "more". Adding "more" is a classic, very noticeable error.', '[{"en":"She is more intelligent than her brother.","pt":"Ela é mais inteligente do que o irmão."},{"en":"This is the best coffee I''ve ever had.","pt":"Este é o melhor café que alguma vez bebi."},{"en":"He runs as fast as a cheetah.","pt":"Ele corre tão rápido quanto um guepardo."}]'::jsonb, '[{"q":"\"She runs ___ than her sister.\"","opts":["more fast","faster","most fast","more faster"],"ans":1},{"q":"\"This is the ___ day of my life!\"","opts":["more good","gooder","best","most good"],"ans":2},{"q":"\"He is ___ as tall ___ his father.\"","opts":["as / than","so / as","as / as","than / as"],"ans":2},{"q":"\"The traffic is ___ in the morning.\"","opts":["more bad","baddest","worse","worst"],"ans":2}]'::jsonb),
('g28', 'Present Perfect Continuous', 'How long have you been doing this?', 'Subject + have/has + been + V-ing', '💡 KEY difference: "I have read 50 pages" (RESULT counts — completed amount) vs "I have been reading" (ACTIVITY is the focus — result doesn''t matter). Stative verbs (know, love, own, want) CANNOT use continuous!', '[{"en":"I have been learning English for two years.","pt":"Estou a aprender inglês há dois anos."},{"en":"She looks tired — she has been working all night.","pt":"Ela parece cansada — esteve a trabalhar toda a noite."},{"en":"How long have you been waiting?","pt":"Há quanto tempo estás à espera?"}]'::jsonb, '[{"q":"\"I ___ English for three years.\"","opts":["am learning","learn","have been learning","was learning"],"ans":2},{"q":"\"She looks exhausted — she ___ all day.\"","opts":["worked","has worked","has been working","is working"],"ans":2},{"q":"Which verb CANNOT use continuous?","opts":["work","run","know","study"],"ans":2},{"q":"\"How long ___ here?\"","opts":["you are living","you have lived","have you been living","are you living"],"ans":2}]'::jsonb),
('g29', 'Common English Idioms', 'Sound like a native — master figures of speech', 'Idioms = fixed expressions whose meaning ≠ the literal words', '💡 NEVER translate idioms word-by-word! "It''s raining cats and dogs" does NOT mean animals are falling from the sky — it means heavy rain. Context and fixed learning are the keys!', '[{"en":"The new car cost an arm and a leg.","pt":"O carro novo custou uma fortuna."},{"en":"Let''s get the ball rolling on this project.","pt":"Vamos começar/pôr o projecto a andar."},{"en":"She let the cat out of the bag about the surprise.","pt":"Ela revelou o segredo sobre a surpresa."}]'::jsonb, '[{"q":"\"Break a leg!\" means...","opts":["Be careful","Good luck","Hurry up","Start over"],"ans":1},{"q":"\"Once in a blue moon\" means...","opts":["Every month","Very rarely","At night","Very often"],"ans":1},{"q":"\"Let''s call it a day\" means...","opts":["Name the day","Stop working","Plan the day","The day is long"],"ans":1},{"q":"\"It cost an arm and a leg\" means...","opts":["It was painful","It was very expensive","It required effort","It was heavy"],"ans":1}]'::jsonb),
('g30', 'Punctuation & Apostrophes', 'Its, it''s, whose, who''s — the details that matter', 'Apostrophe: possession (John''s) & contraction (don''t) | ITS vs IT''S', '💡 The FASTEST way to check: replace with "it is" or "it has". If it makes sense → use IT''S. If not → use ITS. "The dog hurt it''s paw" → "The dog hurt it is paw" ✗ → use ITS!', '[{"en":"It''s a beautiful day, isn''t it?","pt":"É um lindo dia, não é?"},{"en":"The dog wagged its tail happily.","pt":"O cão abanou a cauda alegremente."},{"en":"I visited London, Paris, and Rome.","pt":"Visitei Londres, Paris e Roma."}]'::jsonb, '[{"q":"\"The cat licked ___ paw.\"","opts":["it''s","its","its''","it''s''s"],"ans":1},{"q":"\"___ going to the party?\" (who is)","opts":["Whose","Who''s","Whos''","Whose''"],"ans":1},{"q":"\"I saw the man ___ wallet was stolen.\"","opts":["who''s","whose","which","that''s"],"ans":1},{"q":"\"___ my friend Tom.\" (= he is)","opts":["Its","Its''","He''s","Hes"],"ans":2}]'::jsonb)
on conflict (id) do update set
  title = excluded.title,
  subtitle = excluded.subtitle,
  formula = excluded.formula,
  tip = excluded.tip,
  examples = excluded.examples,
  quiz = excluded.quiz;
